在家目录创建 its.sh
#!/usr/bin/env bash

set -euo pipefail

URL=&quot;its4.pku.edu.cn/cas/ITSClient&quot;
IPRANGE=&quot;free&quot;

echo &quot;========== ITS CLI ==========&quot;

while true; do
  echo &quot;Choose an action:&quot;
  echo &quot;  1) Connect&quot;
  echo &quot;  2) Disconnect&quot;
  read -r -p &quot;Enter 1 or 2: &quot; choice

  case &quot;$choice&quot; in
    1)
      CMD=&quot;open&quot;
      break
      ;;
    2)
      CMD=&quot;disconnect&quot;
      break
      ;;
    *)
      echo &quot;Invalid input. Please try again.&quot;
      ;;
  esac
done

while true; do
  read -r -p &quot;Enter student/staff ID: &quot; USERNAME
  if [[ -n &quot;${USERNAME// }&quot; ]]; then
    break
  fi
  echo &quot;ID cannot be empty.&quot;
done

while true; do
  read -r -s -p &quot;Enter password: &quot; PASSWORD
  echo
  if [[ -n &quot;$PASSWORD&quot; ]]; then
    break
  fi
  echo &quot;Password cannot be empty.&quot;
done

echo
echo &quot;Sending request...&quot;

RESPONSE=$(
  curl -sS --connect-timeout 10 --max-time 20 --config - &lt;&lt;EOF
url = &quot;$URL&quot;
request = &quot;POST&quot;
header = &quot;Content-Type: application/x-www-form-urlencoded&quot;
data-urlencode = &quot;cmd=$CMD&quot;
data-urlencode = &quot;username=$USERNAME&quot;
data-urlencode = &quot;password=$PASSWORD&quot;
data-urlencode = &quot;iprange=$IPRANGE&quot;
EOF
) || {
  echo &quot;Request failed: network error or server unreachable.&quot;
  exit 1
}

echo &quot;Server response:&quot;
echo &quot;$RESPONSE&quot;
之后加入到环境变量中（下面是 bash 版本的示例，如果是 zsh 类似）
mv its.sh its
chmod +x its
mkdir -p ~/bin
mv its ~/bin/
echo &#039;export PATH=&quot;$HOME/bin:$PATH&quot;&#039; &gt;&gt; ~/.bashrc
source ~/.bashrc
which its

